class Solution {
public:
    int numberOfWays(int n, int x) {
        int MOD = 1e9 + 7;
        vector<int> dp(x + 1, 0);
        dp[0] = 1;
        for (int i = 1; i <= x; i++) {
            for (int j = i; j <= x; j++) {
                dp[j] = (dp[j] + dp[j - i]) % MOD;
            }
        }
        return dp[x];
    }
};
